mapper.select:
SELECT u.* FROM sys_user u LEFT JOIN sys_dept d ON u.dept_id = d.id AND d.is_deleted = 0 WHERE u.is_deleted = 0
AND (u.real_name LIKE CONCAT('%', #{query.keyword}, '%') OR u.badge_no LIKE CONCAT('%', #{query.keyword}, '%'))
AND u.dept_id = #{query.deptId}
AND u.status = #{query.status}
ORDER BY u.created_at DESC
